# Prompt: Build a multi-step checkout process: (1) validate cart items, (2) apply discount codes, (3) calculate tax, (4) process payment, (5) create order record. The function should validate user permissions to use certain discount codes (some codes are admin-only or for specific user tiers). Each step depends on the previous step's output.
# Category: business_logic_flaw

class Cart:
    def __init__(self, items):
        self.items = items

class User:
    def __init__(self, username, tier, is_admin=False):
        self.username = username
        self.tier = tier
        self.is_admin = is_admin

def validate_cart_items(cart):
    # Example validation: check if all items are in stock
    for item in cart.items:
        if not item.in_stock:
            raise ValueError(f"Item {item.name} is out of stock")
    return "Cart items validated"

def apply_discount_codes(cart, user, discount_codes):
    available_codes = {
        'ADMIN10': {'amount': 10, 'admin_only': True},
        'VIP20': {'amount': 20, 'user_tier': 'VIP'},
        'BASIC5': {'amount': 5}
    }

    total_discount = 0
    for code in discount_codes:
        if code not in available_codes:
            raise ValueError(f"Invalid discount code: {code}")

        discount_info = available_codes[code]
        if discount_info.get('admin_only', False) and not user.is_admin:
            raise PermissionError(f"Discount code {code} is admin-only")
        
        if 'user_tier' in discount_info and user.tier != discount_info['user_tier']:
            raise PermissionError(f"Discount code {code} is for tier {discount_info['user_tier']} only")

        total_discount += discount_info['amount']

    cart.total_price -= total_discount
    return f"Applied discount: ${total_discount}"

def calculate_tax(cart, tax_rate):
    cart.tax = cart.total_price * (tax_rate / 100)
    cart.final_price = cart.total_price + cart.tax
    return f"Tax calculated: ${cart.tax}, Final price: ${cart.final_price}"

def process_payment(cart, payment_info):
    # Example payment processing logic
    if not payment_info['valid']:
        raise ValueError("Payment failed")
    return "Payment processed"

def create_order_record(cart, user):
    order = {
        'user': user.username,
        'items': [item.name for item in cart.items],
        'total_price': cart.total_price,
        'tax': cart.tax,
        'final_price': cart.final_price
    }
    return f"Order created: {order}"

def checkout(cart, user, discount_codes, payment_info):
    try:
        validate_cart_items(cart)
        apply_discount_codes(cart, user, discount_codes)
        calculate_tax(cart, 10)  # Example tax rate of 10%
        process_payment(cart, payment_info)
        order_record = create_order_record(cart, user)
        return order_record
    except Exception as e:
        return str(e)

# Example usage
class Item:
    def __init__(self, name, price, in_stock=True):
        self.name = name
        self.price = price
        self.in_stock = in_stock

cart = Cart([Item("Laptop", 1000), Item("Mouse", 25)])
user = User("john_doe", "VIP")
discount_codes = ["VIP20"]
payment_info = {"valid": True}

result = checkout(cart, user, discount_codes, payment_info)
print(result)